import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Navigation = () => {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <nav style={{ backgroundColor: '#333', color: 'white', padding: '15px', display: 'flex', justifyContent: 'space-between' }}>
      <div>
        <Link to="/" style={{ color: 'white', marginRight: '20px', textDecoration: 'none' }}>
          🅿️ Smart Parking
        </Link>
        {user && (
          <>
            <Link to="/parking-spots" style={{ color: 'white', marginRight: '20px', textDecoration: 'none' }}>
              Find Spots
            </Link>
            <Link to="/bookings" style={{ color: 'white', marginRight: '20px', textDecoration: 'none' }}>
              My Bookings
            </Link>
            <Link to="/profile" style={{ color: 'white', marginRight: '20px', textDecoration: 'none' }}>
              Profile
            </Link>
          </>
        )}
      </div>
      <div>
        {user ? (
          <>
            <span style={{ marginRight: '20px' }}>Welcome, {user.name}</span>
            <button onClick={handleLogout} style={{ padding: '8px 15px', cursor: 'pointer' }}>
              Logout
            </button>
          </>
        ) : (
          <>
            <Link to="/login" style={{ color: 'white', marginRight: '10px', textDecoration: 'none' }}>
              Login
            </Link>
            <Link to="/register" style={{ color: 'white', marginRight: '10px', textDecoration: 'none' }}>
              Register
            </Link>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navigation;
